// Define o pilar do dia e a query de tendências correspondente.
const day = new Date().getDay(); // 0=Dom .. 6=Sáb
const map = {
  1: { pilar: 'engenharia', search_query: '"automação de processos IA PME 2026" OR "inteligência artificial pequenas empresas"' },
  3: { pilar: 'pme', search_query: '"gestão digital PME Brasil 2026" OR "operações digitais escritório advocacia contabilidade"' },
  5: { pilar: 'bastidores', search_query: '"desenvolvimento de software sob medida Brasil" OR "branding estúdio tech 2026"' }
};
const ctx = map[day] || map[3];
return [{ json: { pilar: ctx.pilar, search_query: ctx.search_query, today: new Date().toISOString().slice(0, 10) } }];

// Extrai os 5 primeiros títulos do RSS do Google News.
const xml = $input.first().json.data || '';
const items = [...xml.matchAll(/<item>([\s\S]*?)<\/item>/g)].slice(0, 5);
const clean = (s) => (s || '').replace(/<!\[CDATA\[|\]\]>/g, '').replace(/<[^>]+>/g, '').trim();
const trends = items
  .map((m) => clean((m[1].match(/<title>([\s\S]*?)<\/title>/) || [])[1]))
  .filter(Boolean);
const ctx = $('Set Pilar Context').first().json;
return [{ json: { ...ctx, trends: trends.join('\n') } }];

// Monta o corpo da requisição para a Claude API.
const ctx = $input.first().json;
const system = `Você é o ghostwriter da Sapienza Labs, estúdio de software sob medida para PMEs da Baixada Fluminense (RJ). Escreve na voz de Marc Jaderson — direto, técnico, sem firula. Fala com donos de PMEs: advogados, contadores, médicos em clínicas pequenas.

Tom: sem bullshit corporativo. Concreto, exemplos reais, linguagem acessível mas não infantil. PT-BR. Primeira pessoa do singular quando fizer sentido.

Retorne APENAS um JSON válido com esta estrutura, sem markdown, sem explicações:
{
  "title": "Título do artigo (max 70 chars, SEO-friendly)",
  "slug": "slug-do-artigo-sem-acentos",
  "excerpt": "Resumo de 2-3 linhas para SEO e redes sociais.",
  "tags": ["tag1", "tag2", "tag3"],
  "content": "Conteúdo completo do artigo em Markdown. Mínimo 800 palavras. Inclui: introdução direta (sem 'neste artigo vamos ver'), 3-4 seções com H2, exemplos concretos de PMEs brasileiras, CTA final para contato com a Sapienza Labs."
}`;
const user = `Pilar: ${ctx.pilar}
Data: ${ctx.today}
Tendências identificadas:
${ctx.trends}

Gere um artigo para o blog da Sapienza Labs sobre este pilar, usando as tendências como gancho mas com ângulo próprio e opinião clara.`;
const anthropicBody = {
  model: 'claude-sonnet-4-6',
  max_tokens: 4000,
  system,
  messages: [{ role: 'user', content: user }]
};
return [{ json: { ...ctx, anthropicBody } }];

// Faz parse do JSON do artigo e monta o arquivo MDX + payload do GitHub.
const resp = $input.first().json;
const ctx = $('Build Claude Request').first().json;
let text = Array.isArray(resp.content)
  ? resp.content.filter((b) => b.type === 'text').map((b) => b.text).join('')
  : '';
text = text.trim().replace(/^```(json)?/i, '').replace(/```$/, '').trim();
const article = JSON.parse(text);
const date = ctx.today;
const mdx = [
  '---',
  `title: ${JSON.stringify(article.title)}`,
  `slug: ${JSON.stringify(article.slug)}`,
  `excerpt: ${JSON.stringify(article.excerpt)}`,
  `pillar: ${JSON.stringify(ctx.pilar)}`,
  `publishedAt: ${JSON.stringify(date)}`,
  'author: "Marc Jaderson"',
  `tags: ${JSON.stringify(article.tags || [])}`,
  'coverImage: "/og-image.png"',
  '---',
  '',
  article.content,
  ''
].join('\n');
const filename = `${date}-${article.slug}.mdx`;
const path = `app/blog/posts/${filename}`;
const contentB64 = Buffer.from(mdx, 'utf-8').toString('base64');
const githubBody = {
  message: `feat(blog): add post '${article.title}' [${ctx.pilar}]`,
  content: contentB64,
  branch: 'main'
};
return [{ json: { path, filename, title: article.title, pilar: ctx.pilar, githubBody } }];

// Monta a legenda do Instagram e o post do LinkedIn a partir do payload do webhook.
const p = $('Webhook Social (da GitHub Action)').first().json.body || {};
const tags = (p.tags || []).slice(0, 2).map((t) => '#' + String(t).replace(/[^a-zA-Z0-9]/g, '')).join(' ');
const igCaption = `${p.title}

${p.excerpt}

Artigo completo 👇
${p.url}

${tags} #PME #sapienzalabs #softwaresobmedida`;
const liText = `${p.title}

${p.excerpt}

→ ${p.url}

Publico sobre ${p.pillar} toda semana. Segue o perfil para acompanhar.`;
return [{ json: { ...p, igCaption, liText, image_url: 'https://sapienzalabs.com.br/og-image.png' } }];
